// utils/schemaBuilder.ts

import * as Yup from "yup";
import type {FieldValues} from 'react-hook-form';
import type {ICombined, IFormElement, IGroup, IObjectGroup} from '@lmb-it/kitsconcerto-types';
import {formFileValidation} from "./helpers";

// A helper type for the shape object used by Yup.
type YupShape = { [key: string]: Yup.AnySchema };


const cloneSchema = (schema: Yup.AnySchema) => {
    // Yup schemas are immutable but need re-instantiation
    return schema.clone();
};

const buildShape = <T extends FieldValues>(
    elements: IFormElement<T>[],
    id: string
): YupShape => {
    const shape = elements.reduce((acc: YupShape, element) => {
        if ('displayOnly' in element && element.displayOnly) return acc;

        const fieldId = element.id as string;

        // FILE / IMAGE
        if (element.type === 'File' || element.type === 'Image') {
            acc[fieldId] = formFileValidation({
                max: (element as any).limit,
                maxKB: (element as any).maxFileSize,
                minKB: (element as any).minFileSize,
            });
            return acc;
        }

        // OBJECT (single nested level)
        if (element.type === 'Object') {
            const nested = (element as IObjectGroup<T>).elements;
            if (typeof nested !== 'function') {
                acc[fieldId] = Yup.object().shape(
                    buildShape(nested, fieldId)
                );
            }
            return acc;
        }

        // COMBINED — validate parent schema only, skip children
        if (element.type === 'Combined') {
            if (element.schema) {
                acc[fieldId] = cloneSchema(element.schema);
            }
            return acc;
        }

        // GROUP (array of objects)
        if (element.type === 'Group') {
            const nested = (element as IGroup<T>).elements;
            if (typeof nested !== 'function') {
                acc[fieldId] = Yup.array().of(
                    Yup.object().shape(
                        buildShape(nested, fieldId)
                    )
                );
            }
            return acc;
        }

        // SIMPLE FIELD — 🔥 CLONE REQUIRED 🔥
        if (element.schema) {
            acc[fieldId] = cloneSchema(element.schema);
        }

        return acc;
    }, {});

    return shape;
};


/**
 * Recursively builds a Yup validation schema from an array of form element definitions.
 *
 * @param {IFormElement<T>[]} elements - The array of element configurations.
 * @param id
 * @returns {Yup.ObjectSchema<any>} A Yup object schema representing the form structure.
 */
export const schemaBuilder = <T extends FieldValues>(
    elements: IFormElement<T>[], id:string
): Yup.ObjectSchema<any> => {
    // 1. Build the complete, nested, plain JavaScript object shape.
    const finalShape = buildShape(elements, id);

    // 2. Create the final Yup schema ONCE with the full context.
    //    Yup can now correctly resolve all '../' and '../../' paths.
    return Yup.object(finalShape);
};

